fn init_tracing() -> Option<opentelemetry_sdk::trace::SdkTracerProvider> {
    let fmt_layer = tracing_subscriber::fmt::layer().json();
    let filter = EnvFilter::try_from_default_env()
        .unwrap_or_else(|_| EnvFilter::new("info"));

    let registry = tracing_subscriber::registry()
        .with(filter)
        .with(fmt_layer);

    if std::env::var("OTEL_EXPORTER_OTLP_ENDPOINT").is_ok() {
        use opentelemetry::trace::TracerProvider;
        match opentelemetry_otlp::SpanExporter::builder()
            .with_tonic()
            .build()
        {
            Ok(exporter) => {
                let provider = opentelemetry_sdk::trace::SdkTracerProvider::builder()
                    .with_batch_exporter(exporter)
                    .build();
                let tracer = provider.tracer("app");
                opentelemetry::global::set_tracer_provider(provider.clone());
                let otel_layer = tracing_opentelemetry::layer().with_tracer(tracer);
                registry.with(otel_layer).init();
                Some(provider)
            }
            Err(e) => {
                eprintln!("Failed to initialize OTel exporter (OTEL_EXPORTER_OTLP_ENDPOINT is set but exporter creation failed): {e}");
                registry.init();
                None
            }
        }
    } else {
        registry.init();
        None
    }
}

