async fn health(
    axum::extract::State(state): axum::extract::State<app_state::AppState>,
) -> axum::Json<serde_json::Value> {
    let db_ok = sea_orm::ConnectionTrait::execute(
        &state.db,
        sea_orm::Statement::from_string(
            sea_orm::DatabaseBackend::Postgres,
            "SELECT 1",
        ),
    )
    .await
    .is_ok();
    axum::Json(serde_json::json!({
        "status": if db_ok { "ok" } else { "degraded" },
        "db": if db_ok { "connected" } else { "unreachable" },
    }))
}

async fn health_ready(
    axum::extract::State(state): axum::extract::State<app_state::AppState>,
) -> axum::Json<serde_json::Value> {
    let db_ok = sea_orm::ConnectionTrait::execute(
        &state.db,
        sea_orm::Statement::from_string(
            sea_orm::DatabaseBackend::Postgres,
            "SELECT 1",
        ),
    )
    .await
    .is_ok();

    // Check workflow definitions exist (informational, not a failure)
    let workflow_status = async {
        use sea_orm::{FromQueryResult, JsonValue};
        let result = JsonValue::find_by_statement(sea_orm::Statement::from_string(
            sea_orm::DatabaseBackend::Postgres,
            "SELECT count(*)::int AS cnt FROM platform.workflow_definition",
        ))
        .one(&state.db)
        .await
        .ok()
        .flatten();
        match result {
            Some(val) => {
                let cnt = val.get("cnt").and_then(|v| v.as_i64()).unwrap_or(0);
                if cnt > 0 { "ok" } else { "no_definitions" }
            }
            None => "no_definitions",
        }
    }.await;

    // Check RLS session vars can be set and read back within a transaction
    let rls_ok = async {
        use sea_orm::TransactionTrait;
        let tx = state.db.begin().await.ok()?;
        sea_orm::ConnectionTrait::execute(
            &tx,
            sea_orm::Statement::from_string(
                sea_orm::DatabaseBackend::Postgres,
                "SELECT set_config('app.current_api_key', 'health-check', true)",
            ),
        ).await.ok()?;
        // Read back to verify round-trip
        let readback = sea_orm::ConnectionTrait::query_one(
            &tx,
            sea_orm::Statement::from_string(
                sea_orm::DatabaseBackend::Postgres,
                "SELECT current_setting('app.current_api_key') AS val",
            ),
        ).await.ok()?;
        let val: String = readback?.try_get("", "val").ok()?;
        tx.commit().await.ok()?;
        if val == "health-check" { Some(()) } else { None }
    }.await.is_some();

    let uptime_secs = START_TIME.get().map(|s| s.elapsed().as_secs()).unwrap_or(0);

    axum::Json(serde_json::json!({
        "status": if db_ok && rls_ok { "ok" } else { "degraded" },
        "db": if db_ok { "connected" } else { "unreachable" },
        "workflow": workflow_status,
        "rls": if rls_ok { "ok" } else { "error" },
        "uptime_seconds": uptime_secs,
    }))
}

